let TrusteePageSessions =
    pageViews
    | where timestamp {TimeRange}
    | where url contains "/trustees"
    | summarize by session_Id;
let FilterModifiedSessions =
    customEvents
    | where timestamp {TimeRange}
    | where name == "Trustee District Filter Changed"
    | where tostring(customDimensions.isDefault) != "true"
    | summarize by session_Id;
let TotalSessions = toscalar(TrusteePageSessions | count);
let ModifiedSessions = toscalar(
    FilterModifiedSessions
    | join kind=inner TrusteePageSessions on session_Id
    | count
);
print
    TotalSessions = TotalSessions,
    ModifiedSessions = ModifiedSessions,
    ModificationRate = round(iif(TotalSessions > 0, todouble(ModifiedSessions) / todouble(TotalSessions) * 100, 0.0), 1)

let TrusteePageSessions =
    pageViews
    | where timestamp {TimeRange}
    | where url contains "/trustees"
    | summarize by session_Id;
let ClearSessions =
    customEvents
    | where timestamp {TimeRange}
    | where name == "Trustee District Filter Cleared"
    | summarize by session_Id;
let TotalSessions = toscalar(TrusteePageSessions | count);
let ClearedSessions = toscalar(
    ClearSessions
    | join kind=inner TrusteePageSessions on session_Id
    | count
);
print
    TotalSessions = TotalSessions,
    ClearedSessions = ClearedSessions,
    ClearRate = round(iif(TotalSessions > 0, todouble(ClearedSessions) / todouble(TotalSessions) * 100, 0.0), 1)
